const LANG_COLORS = {
  JavaScript: '#f1e05a',
  TypeScript: '#3178c6',
  Python: '#3572A5',
  Java: '#b07219',
  'C#': '#178600',
  'C++': '#f34b7d',
  C: '#555555',
  PHP: '#4F5D95',
  Ruby: '#701516',
  Go: '#00ADD8',
  Rust: '#dea584',
  Kotlin: '#A97BFF',
  Swift: '#F05138',
  HTML: '#e34c26',
  CSS: '#563d7c',
  Shell: '#89e051',
  Dart: '#00B4AB',
  Vue: '#41b883',
};

let currentSort = 'stars';
let currentOrder = 'desc';
let reposCache = [];

export function renderRepoList(repos, container) {
  reposCache = repos;
  currentSort = 'stars';
  currentOrder = 'desc';
  _render(container);
}

function _render(container) {
  const sorted = [...reposCache].sort(comparator());

  const controls = `
    <div class="d-flex align-items-center justify-content-between flex-wrap gap-2 mb-3">
      <span class="text-muted" style="font-size:0.875rem">
        ${reposCache.length} repositório${reposCache.length !== 1 ? 's' : ''}
      </span>
      <div class="sort-controls">
        <span class="text-muted me-1" style="font-size:0.82rem">Ordenar por:</span>
        ${sortBtn('stars', 'Estrelas')}
        ${sortBtn('name', 'Nome')}
        ${sortBtn('updated_at', 'Atualização')}
        <button class="btn btn-sm btn-sort btn-outline-secondary ms-1" id="btn-order" title="Inverter ordem">
          <i class="bi bi-arrow-${currentOrder === 'desc' ? 'down' : 'up'}"></i>
        </button>
      </div>
    </div>
  `;

  const cards = sorted.map(repo => repoCard(repo)).join('');

  container.innerHTML = `
    <div id="sort-controls-wrapper">${controls}</div>
    <div class="d-flex flex-column gap-2">${cards}</div>
  `;

  container.querySelectorAll('[data-sort]').forEach(btn => {
    btn.addEventListener('click', () => {
      if (currentSort === btn.dataset.sort) {
        currentOrder = currentOrder === 'desc' ? 'asc' : 'desc';
      } else {
        currentSort = btn.dataset.sort;
        currentOrder = btn.dataset.sort === 'name' ? 'asc' : 'desc';
      }
      _render(container);
    });
  });

  container.querySelector('#btn-order').addEventListener('click', () => {
    currentOrder = currentOrder === 'desc' ? 'asc' : 'desc';
    _render(container);
  });
}

function sortBtn(key, label) {
  const active = currentSort === key ? 'btn-secondary' : 'btn-outline-secondary';
  return `<button class="btn btn-sm btn-sort ${active}" data-sort="${key}">${label}</button>`;
}

function comparator() {
  return (a, b) => {
    let valA, valB;

    if (currentSort === 'stars') {
      valA = a.stargazers_count;
      valB = b.stargazers_count;
    } else if (currentSort === 'name') {
      valA = a.name.toLowerCase();
      valB = b.name.toLowerCase();
    } else {
      valA = new Date(a.updated_at);
      valB = new Date(b.updated_at);
    }

    if (valA < valB) return currentOrder === 'asc' ? -1 : 1;
    if (valA > valB) return currentOrder === 'asc' ? 1 : -1;
    return 0;
  };
}

function repoCard(repo) {
  const lang = repo.language;
  const langColor = lang ? (LANG_COLORS[lang] || '#8b8b8b') : null;
  const langBadge = lang
    ? `<span><span class="lang-dot" style="background:${langColor}"></span>${lang}</span>`
    : '';

  const desc = repo.description
    ? `<div class="repo-desc">${repo.description}</div>`
    : '';

  const hash = `#/repo/${encodeURIComponent(repo.full_name)}`;

  return `
    <a href="${hash}" class="repo-card">
      <div class="repo-name">${repo.name}</div>
      ${desc}
      <div class="repo-meta">
        <span class="stars"><i class="bi bi-star-fill me-1"></i>${repo.stargazers_count.toLocaleString()}</span>
        ${langBadge}
      </div>
    </a>
  `;
}
