import { fetchRepo } from '../api.js';
import { renderSpinner } from '../components/spinner.js';

export async function renderRepository(app, { fullName }) {
  app.innerHTML = `
    <div class="mb-3">
      <a id="back-btn" href="#/" class="btn btn-sm btn-outline-secondary">
        <i class="bi bi-arrow-left me-1"></i>Voltar
      </a>
    </div>
    ${renderSpinner()}
  `;

  try {
    const repo = await fetchRepo(fullName);
    const owner = repo.owner.login;

    app.innerHTML = `
      <div class="mb-3">
        <a href="#/user/${encodeURIComponent(owner)}" class="btn btn-sm btn-outline-secondary">
          <i class="bi bi-arrow-left me-1"></i>Voltar para ${owner}
        </a>
      </div>
      <div class="repo-detail-card">
        <div class="d-flex align-items-center gap-2 mb-1">
          <img
            src="${repo.owner.avatar_url}"
            alt="${owner}"
            style="width:28px;height:28px;border-radius:50%"
          />
          <span class="text-muted" style="font-size:0.9rem">${owner}</span>
        </div>

        <h2 class="repo-title mb-2">${repo.name}</h2>

        ${repo.description ? `<p class="text-muted mb-3">${repo.description}</p>` : ''}

        <div class="d-flex flex-wrap gap-2 mb-4">
          <span class="stat-badge">
            <i class="bi bi-star-fill text-warning"></i>
            ${repo.stargazers_count.toLocaleString()} estrelas
          </span>
          ${repo.language ? `
          <span class="stat-badge">
            <i class="bi bi-code-slash"></i>
            ${repo.language}
          </span>` : ''}
          <span class="stat-badge">
            <i class="bi bi-git"></i>
            ${repo.forks_count.toLocaleString()} forks
          </span>
          <span class="stat-badge">
            <i class="bi bi-eye"></i>
            ${repo.watchers_count.toLocaleString()} watchers
          </span>
        </div>

        <a
          href="${repo.html_url}"
          target="_blank"
          rel="noopener noreferrer"
          class="btn btn-dark"
        >
          <i class="bi bi-box-arrow-up-right me-2"></i>Ver no GitHub
        </a>
      </div>
    `;
  } catch (err) {
    app.innerHTML = `
      <div class="mb-3">
        <a href="#/" class="btn btn-sm btn-outline-secondary">
          <i class="bi bi-arrow-left me-1"></i>Voltar
        </a>
      </div>
      <div class="error-box">
        <span class="icon">😕</span>
        <p>Repositório não encontrado.</p>
      </div>
    `;
  }
}
