import { fetchUser, fetchRepos } from '../api.js';
import { renderUserCard } from '../components/userCard.js';
import { renderRepoList } from '../components/repoList.js';
import { renderSpinner } from '../components/spinner.js';

export async function renderUser(app, { username }) {
  app.innerHTML = `
    <div class="mb-3">
      <a href="#/" class="btn btn-sm btn-outline-secondary">
        <i class="bi bi-arrow-left me-1"></i>Voltar
      </a>
    </div>
    ${renderSpinner()}
  `;

  try {
    const [user, repos] = await Promise.all([
      fetchUser(username),
      fetchRepos(username),
    ]);

    app.innerHTML = `
      <div class="mb-3">
        <a href="#/" class="btn btn-sm btn-outline-secondary">
          <i class="bi bi-arrow-left me-1"></i>Voltar
        </a>
      </div>
      <div class="row g-4">
        <div class="col-md-4">
          ${renderUserCard(user)}
        </div>
        <div class="col-md-8">
          <div id="repo-list"></div>
        </div>
      </div>
    `;

    const repoListEl = app.querySelector('#repo-list');
    renderRepoList(repos, repoListEl);
  } catch (err) {
    const msg = err.response?.status === 404
      ? `Usuário <strong>${username}</strong> não encontrado.`
      : 'Erro ao conectar com a API do GitHub. Tente novamente.';

    app.innerHTML = `
      <div class="mb-3">
        <a href="#/" class="btn btn-sm btn-outline-secondary">
          <i class="bi bi-arrow-left me-1"></i>Voltar
        </a>
      </div>
      <div class="error-box">
        <span class="icon">😕</span>
        <p>${msg}</p>
      </div>
    `;
  }
}
