export function renderUserCard(user) {
  const email = user.email
    ? `<span class="stat-item"><i class="bi bi-envelope me-1"></i>${user.email}</span>`
    : '';

  const bio = user.bio
    ? `<p class="bio">${user.bio}</p>`
    : '';

  return `
    <div class="profile-card">
      <div class="d-flex align-items-center gap-3 mb-3">
        <img src="${user.avatar_url}" alt="Avatar de ${user.login}" />
        <div>
          <div class="username">${user.name || user.login}</div>
          <div class="text-muted" style="font-size:0.85rem">@${user.login}</div>
        </div>
      </div>
      ${bio}
      <div class="d-flex flex-wrap gap-3">
        <span class="stat-item">
          <i class="bi bi-people me-1"></i>
          <strong>${formatCount(user.followers)}</strong> seguidores
        </span>
        <span class="stat-item">
          <i class="bi bi-person-check me-1"></i>
          <strong>${formatCount(user.following)}</strong> seguindo
        </span>
        ${email}
      </div>
    </div>
  `;
}

function formatCount(n) {
  if (n >= 1000) return `${(n / 1000).toFixed(1)}k`;
  return n;
}
